const body = $input.item.json;
const currentDate = new Date().toISOString();
const { client = {}, brief = {}, pricing = {}, designer = 'خالد عمر' } = body;
const parsedQuantity = Number(brief.quantity || 1);
const basePrice = Number(pricing.basePrice || 0);
const extras = Number(pricing.extras || 0);
const tax = Number(pricing.tax || 0);
const total = Number(pricing.total || 0);
const discount = Number(pricing.discount || 0);
const paidAmount = Number(pricing.paidAmount || 0);
let paymentStatus = 'unpaid';
if (paidAmount >= total && total > 0) paymentStatus = 'paid';
else if (paidAmount > 0) paymentStatus = 'partially_paid';

return [{
  json: {
    action: 'create_order',
    order: {
      id: body.orderId,
      client,
      brief: {
        ...brief,
        quantity: parsedQuantity,
        files: brief.files || []
      },
      pricing: {
        basePrice,
        extras,
        tax,
        total,
        discount,
        paidAmount,
        paymentStatus,
        paymentMethod: pricing.paymentMethod || 'none'
      },
      stage: body.stage || 'intake',
      designer,
      designDrafts: [],
      comments: [],
      createdAt: currentDate,
      logs: [
        {
          stage: body.stage || 'intake',
          time: currentDate,
          note: 'تم إنشاء الطلب واستقبال العميل وحساب الفاتورة المبدئية'
        }
      ]
    }
  }
}];

const body = $input.item.json;
const currentDate = new Date().toISOString();
const order = body.order || {};
const draftUrl = body.draftUrl || body.brief?.draftUrl;
const newDraft = {
  id: 'draft_' + Math.random().toString(36).slice(2, 12),
  version: (order.designDrafts || []).length + 1,
  url: draftUrl,
  uploadedAt: currentDate,
  status: 'pending',
  feedback: ''
};

return [{
  json: {
    action: 'upload_draft',
    order: {
      ...order,
      designDrafts: [...(order.designDrafts || []), newDraft],
      stage: 'design',
      logs: [
        ...(order.logs || []),
        {
          stage: 'design',
          time: currentDate,
          note: `تم رفع نموذج التصميم رقم (${newDraft.version}) من قبل المصمم`
        }
      ]
    }
  }
}];

const body = $input.item.json;
const currentDate = new Date().toISOString();
const order = body.order || {};
const draftId = body.draftId;
const status = body.status || 'approved';
const feedback = body.feedback || '';

const updatedDrafts = (order.designDrafts || []).map((draft) => draft.id === draftId ? { ...draft, status, feedback } : draft);
const approved = status === 'approved';

return [{
  json: {
    action: 'approve_draft',
    order: {
      ...order,
      designDrafts: updatedDrafts,
      stage: approved ? 'printing' : 'design',
      logs: [
        ...(order.logs || []),
        {
          stage: 'design',
          time: currentDate,
          note: `تم ${approved ? 'اعتماد' : 'رفض مع طلب تعديل'} مسودة التصميم رقم (${draftId})`
        },
        ...(approved ? [{
          stage: 'printing',
          time: currentDate,
          note: 'تم إرسال الطلب تلقائياً لقسم الطباعة بعد اعتماد التصميم النهائي'
        }] : [])
      ]
    }
  }
}];

const body = $input.item.json;
const currentDate = new Date().toISOString();
const order = body.order || {};
const pricing = { ...(order.pricing || {}) };
const amount = Number(body.amount || 0);
const paymentMethod = body.paymentMethod || pricing.paymentMethod || 'none';
pricing.paidAmount = Number(pricing.paidAmount || 0) + amount;
pricing.paymentMethod = paymentMethod;
if (pricing.paidAmount >= Number(pricing.total || 0) && Number(pricing.total || 0) > 0) {
  pricing.paymentStatus = 'paid';
} else if (pricing.paidAmount > 0) {
  pricing.paymentStatus = 'partially_paid';
} else {
  pricing.paymentStatus = 'unpaid';
}

return [{
  json: {
    action: 'pay_invoice',
    order: {
      ...order,
      pricing,
      stage: body.stage || order.stage || 'billing',
      logs: [
        ...(order.logs || []),
        {
          stage: 'billing',
          time: currentDate,
          note: `تم دفع مبلغ بقيمة ${amount} ريال بواسطة ${paymentMethod}. المجموع المدفوع: ${pricing.paidAmount} ريال`
        }
      ]
    }
  }
}];

const body = $input.item.json;
const currentDate = new Date().toISOString();
const order = body.order || {};
const targetStage = body.stage || 'billing';
const stageNotes = {
  intake: 'تم استقبال الطلب ودخول مرحلة الاستقبال والبريف',
  design: 'تم نقل الطلب إلى مرحلة التصميم والتعديل',
  printing: 'تم نقل الطلب إلى مرحلة الطباعة والتشغيل',
  billing: 'تم نقل الطلب إلى مرحلة الفوترة والدفع',
  completed: 'تم نقل الطلب إلى مرحلة التسليم والانتهاء'
};

return [{
  json: {
    action: 'change_stage',
    order: {
      ...order,
      stage: targetStage,
      logs: [
        ...(order.logs || []),
        {
          stage: targetStage,
          time: currentDate,
          note: stageNotes[targetStage] || `تم نقل الطلب إلى مرحلة ${targetStage}`
        }
      ]
    }
  }
}];
